from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        # Parse the XML data
        root = etree.fromstring(xml_data)

        # Create XPath query to find student with matching username and password
        xpath_query = f"//student[username='{username}' and password='{password}']"
        students = root.xpath(xpath_query)

        # If no student found, return None
        if not students:
            return None

        # Get the first matching student
        student = students[0]

        # Extract student information
        result = {}
        for child in student:
            result[child.tag] = child.text

        return result

    except etree.XMLSyntaxError:
        return None
    except Exception:
        return None

import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    # Validate domain
    if not domain or not isinstance(domain, str):
        raise ValueError("Invalid domain")

    # Check if subdomain is empty or None
    if not subdomain_prefix or not isinstance(subdomain_prefix, str):
        return f"https://{domain}"

    # Validate subdomain format (alphanumeric, hyphens, dots only, no leading/trailing hyphens or dots)
    if not re.match(r'^[a-zA-Z0-9]([a-zA-Z0-9\-\.]*[a-zA-Z0-9])?$', subdomain_prefix):
        return f"https://{domain}"

    # Additional check to prevent double dots or invalid patterns
    if '..' in subdomain_prefix or subdomain_prefix.startswith('.') or subdomain_prefix.endswith('.'):
        return f"https://{domain}"

    return f"https://{subdomain_prefix}.{domain}"

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id or not isinstance(user_id, str):
        return None

    # Sanitize user_id to prevent path traversal attacks
    import re
    if not re.match(r'^[a-zA-Z0-9_-]+$', user_id):
        return None

    # Ensure api_url ends with a slash before concatenating
    if not api_url.endswith('/'):
        api_url += '/'

    return api_url + user_id

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    try:
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")

