from flask import request, Flask
import yaml
import json

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        yaml_data = request.data.decode('utf-8')
        parsed_data = yaml.safe_load(yaml_data)
        return json.dumps(parsed_data), 200, {'Content-Type': 'application/json'}
    except Exception as e:
        return json.dumps({'error': 'Invalid YAML data'}), 400, {'Content-Type': 'application/json'}
